function findBadgeImage(name) {
  if (!name) return null;
  // Exact match
  if (BADGE_IMAGE_MAP[name]) return BADGE_IMAGE_MAP[name];
  // Try matching after category prefix (e.g., "활동_10회참여" → "10회참여")
  for (const [key, val] of Object.entries(BADGE_IMAGE_MAP)) {
    const parts = key.split('_');
    if (parts.length > 1) {
      const suffix = parts.slice(1).join('_');
      if (suffix === name) return val;
    }
  }
  // Fuzzy: normalize and compare
  const norm = name.replace(/[\s_]/g, '').toLowerCase();
  for (const [key, val] of Object.entries(BADGE_IMAGE_MAP)) {
    const keyNorm = key.replace(/[\s_]/g, '').toLowerCase();
    if (keyNorm.includes(norm) || norm.includes(keyNorm)) return val;
    const parts = key.split('_');
    if (parts.length > 1) {
      const suffixNorm = parts.slice(1).join('_').replace(/[\s_]/g, '').toLowerCase();
      if (suffixNorm.includes(norm) || norm.includes(suffixNorm)) return val;
    }
  }
  return null;
}
